    i_key_pad = xor_data(b"\x36"*64, key)
    return hashlib.sha256(o_key_pad + hashlib.sha256(i_key_pad + message).digest()).hexdigest()

def extract_pwd(html: str):
    # Try to pull password from rendered dashboard
