    m = re.search(r"Password[^A-Za-z0-9]*([A-Za-z0-9_\-!@#$%^&*().,+=:;<>?/\\|`~]+)", html, re.I)
    if m:
        return m.group(1)
    # fallback: look for common template pattern
    m = re.search(r"pwd\s*[:=]\s*([A-Za-z0-9_\-!@#$%^&*().,+=:;<>?/\\|`~]+)", html, re.I)
