#!/usr/bin/env python3
import requests
import hashlib
import re

BASE_URL = "http://crypto.chal.csaw.io:5000"
DB_PATH = "/home/ctfplayer/ctf_files/database.txt"

# N from server_handout.py
N = int(
    "00ab76f585834c3c2b7b7b2c8a04c66571539fa660d39762e338cd8160589f08"
    "e3d223744cb7894ea6b424ebab899983ff61136c8315d9d03aef12bd7c048618"
    "4945998ff80c8d3d59dcb0196fb2c37c43d9cbff751a0745b9d796bcc155cfd18"
    "6a3bb4ff6c43be833ff1322693d8f76418a48a51f43d598d78a642072e9fff533",
    16,
)


def xor_data(a: bytes, b: bytes) -> bytes:
    return bytes(x ^ y for x, y in zip(a, b))


def hmac_sha256_manual(key: bytes, msg: bytes) -> str:
    # Reimplementation matching server_handout.py style
    if len(key) > 64:
        key = hashlib.sha256(key).digest()
    if len(key) < 64:
        key = key + (b"\x00" * (64 - len(key)))

    o_key_pad = xor_data(b"\x5c" * 64, key)
    i_key_pad = xor_data(b"\x36" * 64, key)
    return hashlib.sha256(o_key_pad + hashlib.sha256(i_key_pad + msg).digest()).hexdigest()


def get_password_for_user(username: str) -> str:
    s = requests.Session()

    # SRP bypass with A = 2N (multiple of N but not blocked)
    r = s.post(BASE_URL + "/", data={"username": username, "token1": str(2 * N)})
    r.raise_for_status()
    j = r.json()

    salt = j["nacl"]

    # S = 0 => K = SHA256(b"0")
    k = hashlib.sha256(b"0").digest()
    client_hmac = hmac_sha256_manual(k, salt.encode())

    dash = s.get(BASE_URL + f"/dash/{username}", params={"hmac": client_hmac})
    dash.raise_for_status()

    m = re.search(r"<td>" + re.escape(username) + r"</td>\s*<td>([^<]+)</td>", dash.text)
    if not m:
        raise RuntimeError(f"Could not parse password for {username}")
    return m.group(1)


def main():
    users = []
    with open(DB_PATH, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            users.append(line.rstrip(":"))

    print("[+] Dumping credentials from /dash via SRP A%N==0 bypass")
    for u in users:
        try:
            pw = get_password_for_user(u)
            print(f"{u} -> {pw}")
        except Exception as e:
            print(f"{u} -> ERROR: {e}")


if __name__ == "__main__":
    main()

